-- Change IDENTITY columns from GENERATED ALWAYS to GENERATED BY DEFAULT
-- This allows explicit ID insertion during migration
ALTER TABLE fscn8001_alarm ALTER COLUMN id DROP IDENTITY IF EXISTS;
ALTER TABLE fscn8001_alarm ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY;

ALTER TABLE fscn8001_device ALTER COLUMN id DROP IDENTITY IF EXISTS;
ALTER TABLE fscn8001_device ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY;

ALTER TABLE gb26875_device ALTER COLUMN id DROP IDENTITY IF EXISTS;
ALTER TABLE gb26875_device ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY;

ALTER TABLE gb26875_alarm ALTER COLUMN id DROP IDENTITY IF EXISTS;
ALTER TABLE gb26875_alarm ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY;

ALTER TABLE sys_refresh_tokens ALTER COLUMN id DROP IDENTITY IF EXISTS;
ALTER TABLE sys_refresh_tokens ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY;
